import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export type MetricsPeriod = '1d' | '7d' | '15d' | '30d' | { from: Date; to: Date };

interface MetricsData {
  totalSpend: number;
  totalImpressions: number;
  totalClicks: number;
  totalConversions: number;
  avgCpc: number;
  globalCpa: number;
  dailyData: Array<{
    date: string;
    spend: number;
    impressions: number;
    clicks: number;
    conversions: number;
  }>;
  previousPeriod: {
    totalSpend: number;
    totalImpressions: number;
    totalClicks: number;
    totalConversions: number;
    avgCpc: number;
    globalCpa: number;
  };
}

export function useCompanyMetrics(period: MetricsPeriod) {
  const { user } = useAuth();

  return useQuery({
    queryKey: ['company-metrics', user?.company_id, period],
    queryFn: async (): Promise<MetricsData> => {
      // Calculate date range based on period
      let startDate = new Date();
      let endDate = new Date();
      let previousStartDate = new Date();
      let previousEndDate = new Date();

      if (typeof period === 'string') {
        const days = parseInt(period);
        startDate.setDate(endDate.getDate() - days);
        previousStartDate.setDate(startDate.getDate() - days);
        previousEndDate.setDate(endDate.getDate() - days);
      } else {
        startDate = period.from;
        endDate = period.to;
        const diffTime = Math.abs(endDate.getTime() - startDate.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        previousStartDate.setDate(startDate.getDate() - diffDays);
        previousEndDate.setDate(startDate.getDate());
      }

      const { data: currentData, error: currentError } = await (supabase as any)
        .from('campaign_daily_metrics')
        .select(`
          date,
          spend,
          impressions,
          clicks,
          conversions,
          campaign:campaigns!inner(company_id)
        `)
        .eq('campaign.company_id', user?.company_id)
        .gte('date', startDate.toISOString().split('T')[0])
        .lte('date', endDate.toISOString().split('T')[0])
        .order('date', { ascending: true });

      if (currentError) throw currentError;

      const { data: previousData, error: previousError } = await (supabase as any)
        .from('campaign_daily_metrics')
        .select(`
          spend,
          impressions,
          clicks,
          conversions,
          campaign:campaigns!inner(company_id)
        `)
        .eq('campaign.company_id', user?.company_id)
        .gte('date', previousStartDate.toISOString().split('T')[0])
        .lt('date', previousEndDate.toISOString().split('T')[0]);

      if (previousError) throw previousError;

      // Aggregations
      const aggregate = (data: any[]) => ({
        totalSpend: data.reduce((sum, item) => sum + Number(item.spend), 0),
        totalImpressions: data.reduce((sum, item) => sum + Number(item.impressions), 0),
        totalClicks: data.reduce((sum, item) => sum + Number(item.clicks), 0),
        totalConversions: data.reduce((sum, item) => sum + Number(item.conversions), 0),
      });

      const current = aggregate(currentData || []);
      const previous = aggregate(previousData || []);

      // Group by date for chart
      const dailyMap = (currentData || []).reduce((acc: any, item) => {
        const date = item.date;
        if (!acc[date]) {
          acc[date] = { date, spend: 0, impressions: 0, clicks: 0, conversions: 0 };
        }
        acc[date].spend += Number(item.spend);
        acc[date].impressions += Number(item.impressions);
        acc[date].clicks += Number(item.clicks);
        acc[date].conversions += Number(item.conversions);
        return acc;
      }, {});

      return {
        ...current,
        avgCpc: current.totalClicks > 0 ? current.totalSpend / current.totalClicks : 0,
        globalCpa: current.totalConversions > 0 ? current.totalSpend / current.totalConversions : 0,
        dailyData: Object.values(dailyMap),
        previousPeriod: {
          ...previous,
          avgCpc: previous.totalClicks > 0 ? previous.totalSpend / previous.totalClicks : 0,
          globalCpa: previous.totalConversions > 0 ? previous.totalSpend / previous.totalConversions : 0,
        }
      };
    },
    enabled: !!user?.company_id,
  });
}

import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';

export interface GoogleCampaign {
    id: string;
    name: string;
    status: string;
    impressions: number;
    clicks: number;
    spend: number;
    conversions: number;
    ctr: number;
    avg_cpc: number;
}

export interface AuctionInsight {
    domain: string;
    impression_share: number;
    overlap_rate: number;
    position_above_rate: number;
    top_of_page_rate: number;
}

export interface GeoPerformance {
    city_name: string;
    region_name: string;
    clicks: number;
    cost_micros: number;
    conversions: number;
    impressions: number;
}

export interface GoogleAd {
    id: string;
    google_id: string;
    type: string;
    status: string;
    creative_category: 'VIDEO' | 'IMAGE' | 'TEXT' | 'CAROUSEL';
    creative_elements: string[];
    headlines: string[];
}

export interface GoogleKeyword {
    id: string;
    text: string;
    match_type: string;
    status: string;
    impressions: number;
    clicks: number;
    cost_micros: number;
    conversions: number;
    avg_cpc: number;
}

export function useGoogleAds() {
    const { data: campaigns, isLoading: isLoadingCampaigns } = useQuery({
        queryKey: ['google_campaigns'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('google_campaigns')
                .select('*')
                .order('spend', { ascending: false });

            if (error) throw error;
            return data as unknown as GoogleCampaign[];
        }
    });

    const { data: auctionInsights, isLoading: isLoadingInsights } = useQuery({
        queryKey: ['google_auction_insights'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('google_auction_insights')
                .select('*')
                .order('impression_share', { ascending: false });

            if (error) throw error;
            return data as unknown as AuctionInsight[];
        }
    });

    const { data: geoPerformance, isLoading: isLoadingGeo } = useQuery({
        queryKey: ['google_geo_performance'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('google_geo_performance')
                .select('*')
                .order('clicks', { ascending: false });

            if (error) throw error;
            return data as unknown as GeoPerformance[];
        }
    });

    const { data: ads, isLoading: isLoadingAds } = useQuery({
        queryKey: ['google_ads'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('google_ads')
                .select('*');
            if (error) throw error;
            return data as unknown as GoogleAd[];
        }
    });

    const { data: keywords, isLoading: isLoadingKeywords } = useQuery({
        queryKey: ['google_keywords'],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('google_keywords')
                .select('*');
            if (error) throw error;
            return data as unknown as GoogleKeyword[];
        }
    });

    return {
        campaigns,
        auctionInsights,
        geoPerformance,
        ads,
        keywords,
        isLoading: isLoadingCampaigns || isLoadingInsights || isLoadingGeo || isLoadingAds || isLoadingKeywords
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Policy {
    id: string;
    company_id: string;
    name: string;
    description: string | null;
    scope: string | null;
    campaign_ids: string[] | null;
    brand_name: string | null;
    logo_url: string | null;
    primary_color: string | null;
    secondary_color: string | null;
    accent_color: string | null;
    brand_guidelines: string | null;
    required_keywords: string[] | null;
    prohibited_keywords: string[] | null;
    required_phrases: string[] | null;
    prohibited_phrases: string[] | null;
    min_text_length: number | null;
    max_text_length: number | null;
    requires_logo: boolean | null;
    requires_brand_colors: boolean | null;
    ctr_min: number | null;
    ctr_target: number | null;
    cpc_max: number | null;
    cpc_target: number | null;
    conversions_min: number | null;
    conversions_target: number | null;
    status: string | null;
    is_default: boolean | null;
    created_at: string;
    updated_at: string;
}

export interface CreatePolicyInput {
    name: string;
    description?: string;
    scope?: 'global' | 'campaign';
    campaign_ids?: string[];
    brand_name?: string;
    logo_url?: string;
    primary_color?: string;
    secondary_color?: string;
    accent_color?: string;
    brand_guidelines?: string;
    required_keywords?: string[];
    prohibited_keywords?: string[];
    required_phrases?: string[];
    prohibited_phrases?: string[];
    min_text_length?: number;
    max_text_length?: number;
    requires_logo?: boolean;
    requires_brand_colors?: boolean;
    ctr_min?: number;
    ctr_target?: number;
    cpc_max?: number;
    cpc_target?: number;
    conversions_min?: number;
    conversions_target?: number;
    status?: 'active' | 'draft' | 'archived';
    is_default?: boolean;
}

export interface UpdatePolicyInput extends Partial<CreatePolicyInput> {
    id: string;
}

export function usePolicies() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;

    const policiesQuery = useQuery({
        queryKey: ['policies', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('policies')
                .select('*')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false });

            if (error) throw error;
            return data as Policy[];
        },
        enabled: !!companyId,
    });

    const createPolicy = useMutation({
        mutationFn: async (input: CreatePolicyInput) => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('policies')
                .insert({
                    ...input,
                    company_id: companyId,
                })
                .select()
                .single();

            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['policies', companyId] });
            toast.success('Política criada com sucesso');
        },
        onError: (error) => {
            toast.error(`Erro ao criar política: ${error.message}`);
        },
    });

    const updatePolicy = useMutation({
        mutationFn: async ({ id, ...input }: UpdatePolicyInput) => {
            const { data, error } = await supabase
                .from('policies')
                .update({ ...input, updated_at: new Date().toISOString() })
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['policies', companyId] });
            toast.success('Política atualizada com sucesso');
        },
        onError: (error) => {
            toast.error(`Erro ao atualizar política: ${error.message}`);
        },
    });

    const deletePolicy = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('policies')
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['policies', companyId] });
            toast.success('Política excluída com sucesso');
        },
        onError: (error) => {
            toast.error(`Erro ao excluir política: ${error.message}`);
        },
    });

    return {
        policies: policiesQuery.data || [],
        isLoading: policiesQuery.isLoading,
        error: policiesQuery.error,
        createPolicy,
        updatePolicy,
        deletePolicy,
    };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { toast } from 'sonner';

export interface Tag {
    id: string;
    company_id: string;
    name: string;
    color: string;
    entity_type: 'campaign' | 'creative' | 'audit';
    created_at: string;
}

export interface TagAssignment {
    tag_id: string;
    entity_id: string;
    created_at: string;
    tag?: Tag;
}

export function useTags(entityType?: 'campaign' | 'creative' | 'audit') {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['tags', companyId, entityType],
        queryFn: async (): Promise<Tag[]> => {
            if (!companyId) throw new Error('No company ID');

            let query = supabase
                .from('tags')
                .select('*')
                .eq('company_id', companyId);

            if (entityType) {
                query = query.eq('entity_type', entityType);
            }

            const { data, error } = await query.order('name');
            if (error) throw error;
            return (data || []) as unknown as Tag[];
        },
        enabled: !!companyId,
    });
}

export function useEntityTags(entityId: string, entityType: 'campaign' | 'creative') {
    const tableName = entityType === 'campaign' ? 'campaign_tags' : 'creative_tags';
    const idColumn = entityType === 'campaign' ? 'campaign_id' : 'creative_id';

    return useQuery({
        queryKey: ['entity-tags', entityId],
        queryFn: async (): Promise<TagAssignment[]> => {
            const { data, error } = await (supabase
                .from(tableName) as any)
                .select('*, tag:tags(*)')
                .eq(idColumn, entityId);

            if (error) throw error;
            return (data || []).map((item: any) => ({
                ...item,
                entity_id: item[idColumn]
            }));
        },
        enabled: !!entityId,
    });
}

export function useTagMutations() {
    const { user } = useAuth();
    const queryClient = useQueryClient();
    const companyId = user?.company?.id;

    const createTag = useMutation({
        mutationFn: async (tag: Omit<Tag, 'id' | 'company_id' | 'created_at'>) => {
            if (!companyId) throw new Error('No company ID');
            const { data, error } = await supabase
                .from('tags')
                .insert({ ...tag, company_id: companyId })
                .select()
                .single();
            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['tags'] });
            toast.success('Tag criada com sucesso!');
        },
    });

    const deleteTag = useMutation({
        mutationFn: async (tagId: string) => {
            const { error } = await supabase.from('tags').delete().eq('id', tagId);
            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['tags'] });
            toast.success('Tag excluída!');
        },
    });

    const addTagToEntity = useMutation({
        mutationFn: async ({ tagId, entityId, entityType }: { tagId: string; entityId: string; entityType: 'campaign' | 'creative' }) => {
            const tableName = entityType === 'campaign' ? 'campaign_tags' : 'creative_tags';
            const idColumn = entityType === 'campaign' ? 'campaign_id' : 'creative_id';

            const { data, error } = await supabase
                .from(tableName as any)
                .insert({ tag_id: tagId, [idColumn]: entityId })
                .select()
                .single();
            if (error) throw error;
            return data;
        },
        onSuccess: (_, variables) => {
            queryClient.invalidateQueries({ queryKey: ['entity-tags', variables.entityId] });
            queryClient.invalidateQueries({ queryKey: ['campaigns'] });
            queryClient.invalidateQueries({ queryKey: ['creatives'] });
        },
    });

    const removeTagFromEntity = useMutation({
        mutationFn: async ({ tagId, entityId, entityType }: { tagId: string; entityId: string; entityType: 'campaign' | 'creative' }) => {
            const tableName = entityType === 'campaign' ? 'campaign_tags' : 'creative_tags';
            const idColumn = entityType === 'campaign' ? 'campaign_id' : 'creative_id';

            const { error } = await supabase
                .from(tableName as any)
                .delete()
                .eq('tag_id', tagId)
                .eq(idColumn, entityId);
            if (error) throw error;
        },
        onSuccess: (_, variables) => {
            queryClient.invalidateQueries({ queryKey: ['entity-tags', variables.entityId] });
            queryClient.invalidateQueries({ queryKey: ['campaigns'] });
            queryClient.invalidateQueries({ queryKey: ['creatives'] });
        },
    });

    return { createTag, deleteTag, addTagToEntity, removeTagFromEntity };
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { useToast } from '@/hooks/use-toast';

// Usando tipos do Supabase schema diretamente
export interface User {
    id: string;
    email: string;
    first_name: string;
    last_name: string;
    role: string;
    is_active: boolean;
    avatar_url: string | null;
    created_at: string;
    last_login_at: string | null;
}

export interface UpdateUserInput {
    first_name?: string;
    last_name?: string;
    role?: 'super_admin' | 'company_admin' | 'operador';
    is_active?: boolean;
}

export function useCompanyUsers() {
    const { user } = useAuth();
    const companyId = user?.company?.id;

    return useQuery({
        queryKey: ['company-users', companyId],
        queryFn: async (): Promise<User[]> => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('users')
                .select('id, email, first_name, last_name, role, is_active, avatar_url, created_at, last_login_at')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false });

            if (error) throw error;
            return (data || []) as User[];
        },
        enabled: !!companyId,
        staleTime: 2 * 60 * 1000,
    });
}

export function useUpdateUser() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const queryClient = useQueryClient();
    const { toast } = useToast();

    return useMutation({
        mutationFn: async ({ userId, updates }: { userId: string; updates: UpdateUserInput }) => {
            if (!companyId) throw new Error('No company ID');

            const { data, error } = await supabase
                .from('users')
                .update(updates as Record<string, unknown>)
                .eq('id', userId)
                .eq('company_id', companyId)
                .select()
                .single();

            if (error) throw error;
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['company-users'] });
            toast({
                title: 'Usuário atualizado',
                description: 'As alterações foram salvas.',
            });
        },
        onError: (error) => {
            toast({
                title: 'Erro ao atualizar',
                description: String(error),
                variant: 'destructive',
            });
        },
    });
}

export function useRemoveUser() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const queryClient = useQueryClient();
    const { toast } = useToast();

    return useMutation({
        mutationFn: async (userId: string) => {
            if (!companyId) throw new Error('No company ID');

            // Desativar o usuário ao invés de removê-lo
            const { error } = await supabase
                .from('users')
                .update({ is_active: false })
                .eq('id', userId)
                .eq('company_id', companyId);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['company-users'] });
            toast({
                title: 'Usuário removido',
                description: 'O usuário foi desativado da empresa.',
            });
        },
        onError: (error) => {
            toast({
                title: 'Erro ao remover',
                description: String(error),
                variant: 'destructive',
            });
        },
    });
}
